"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[9027],{82937:e=>{e.exports=JSON.parse('{"tag":{"label":"special needs","permalink":"/docs/tags/special-needs","allTagsPath":"/docs/tags","count":4,"items":[{"id":"Rabbits/illnesses-and-conditions/maxfactor","title":"Max Factor Rabbits","description":"Max Factor rabbits are a rare and unique type of rabbit affected by a genetic mutation that results in unusual physical characteristics. These rabbits have striking appearances due to differences in their fur and limbs. It\u2019s said that the condition is named after a rabbit named Max who was known to have the condition, but not much is known about the defect or its origin. However, the mutation also affects their health and mobility, creating both challenges and specific care needs. Here\u2019s everything you need to know about Max Factor rabbits, from their characteristics to the ethics of breeding them.","permalink":"/docs/Rabbits/illnesses-and-conditions/maxfactor"},{"id":"guinea-pigs/illnesses-and-conditions/satinsyndrome","title":"Satin Syndrome in Guinea Pigs","description":"\u2705 Download our checklist here and bring it to your vet! \u2705","permalink":"/docs/guinea-pigs/illnesses-and-conditions/satinsyndrome"},{"id":"guinea-pigs/illnesses-and-conditions/clubbed-feet","title":"Understanding Clubbed Feet and Limb Deformities in Guinea Pigs","description":"Guinea pigs are known for their sweet personalities and unique charm\u2014but some arrive into rescue with visible physical challenges, including limb deformities commonly referred to as \\"clubbed feet.\\" Understanding this condition is key to providing these special-needs pigs with the quality of life they deserve.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/clubbed-feet"},{"id":"guinea-pigs/breeds-and-genetics/lethalwhite","title":"Understanding Lethal White Guinea Pigs","description":"Guinea pigs are beloved companions known for their sweet nature, vocal personalities, and varied appearances. But within the world of guinea pig care, there\u2019s a little-known and serious condition that deserves more awareness\u2014lethal white syndrome.","permalink":"/docs/guinea-pigs/breeds-and-genetics/lethalwhite"}],"unlisted":false}}')}}]);